import React from 'react';
import { Link } from 'react-router-dom';

const Footer = ({ cyber }) => {
  return (
    <footer className={`footer ${cyber ? 'footer-cyber' : ''}`}>
      <div className="container">
        <div className="footer-content">
          <div className="footer-brand">
            <i className="fas fa-shield-alt"></i>
            <span>BlackCat Cibersecurity</span>
          </div>
          {cyber && (
            <div className="footer-links">
              <Link to="/">Inicio</Link>
              <Link to="/ciberseguridad">Ciberseguridad</Link>
              <Link to="/ciberseguridad#contacto">Contacto</Link>
            </div>
          )}
          <div className="footer-social">
            <a href="#" aria-label="Facebook"><i className="fab fa-facebook"></i></a>
            <a href="#" aria-label="Twitter"><i className="fab fa-twitter"></i></a>
            <a href="#" aria-label="LinkedIn"><i className="fab fa-linkedin"></i></a>
            <a href="#" aria-label="Instagram"><i className="fab fa-instagram"></i></a>
          </div>
        </div>
        <p className="footer-copy">&copy; 2026 BlackCat Ciberseguridad. Todos los derechos reservados.</p>
        {cyber ? (
          <p className="footer-security">
            <i className="fas fa-lock"></i> Conexión Segura |
            <i className="fas fa-shield-alt"></i> Protegido por BlackCat
          </p>
        ) : (
          <p className="footer-practice">Práctica N°4 - Seguridad Digital y Ciberseguridad</p>
        )}
      </div>
    </footer>
  );
};

export default Footer;
